public extension GradientToken {
    func token(for subtheme: Subtheme) -> GradientToken {
        let identifier = self.tokenIdentifier(for: subtheme)
        guard let gradient = Gradients(rawValue: identifier) else {
            return self
        }
        return gradient.token
    }
}

